-- {"operators": "INNER_JOIN,AGGREGATE,UNION,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,OORDER,HISTORY", "ducklake": true}
WITH o_summary AS (SELECT c.C_W_ID, c.C_ID, SUM(o.O_OL_CNT) AS tot FROM dl.CUSTOMER c JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID GROUP BY c.C_W_ID, c.C_ID), h_summary AS (SELECT H_C_W_ID AS w, H_C_ID AS id, COUNT(*) AS n FROM dl.HISTORY GROUP BY H_C_W_ID, H_C_ID) SELECT C_W_ID AS w, C_ID AS id, tot AS metric, 'order_lines' AS src FROM o_summary UNION ALL SELECT w, id, n, 'history_events' FROM h_summary;
